// This file is generated by tools/gen only if it does not already exist.
// Once present, tools/gen never overwrites it - edit freely to add real
// assertions (this scaffold only proves create+read-back with placeholder
// values).
func TestAccTagEmarsys_createAndReadBack(t *testing.T) {
	testAccPreCheck(t)
	resourceName := "matomo_tagmanager_tag_emarsys.test"

	resource.Test(t, resource.TestCase{
		ProtoV6ProviderFactories: testAccProtoV6ProviderFactories,
		Steps: []resource.TestStep{
			{
				Config: testAccTagEmarsysConfig(),
				Check: resource.ComposeAggregateTestCheckFunc(
					resource.TestCheckResourceAttrSet(resourceName, "id"),
				),
			},
			{
				ResourceName:      resourceName,
				ImportState:       true,
				ImportStateVerify: true,
			},
		},
	})
}

func testAccTagEmarsysConfig() string {
	return `
provider "matomo" {}

resource "matomo_site" "test" {
  name = "Generated Emarsys Acceptance Site"
  urls = ["https://acc-generated-emarsys.example.com"]
}

resource "matomo_tagmanager_container" "test" {
  site_id = matomo_site.test.id
  context = "web"
  name    = "Generated Emarsys Acceptance Container"
}

resource "matomo_tagmanager_trigger" "test" {
  container_id = matomo_tagmanager_container.test.id
  type         = "PageView"
  name         = "Generated Emarsys Acceptance Trigger"
}

resource "matomo_tagmanager_tag_emarsys" "test" {
  container_id = matomo_tagmanager_container.test.id
  name         = "generated-test-emarsys"
  fire_trigger_ids = [matomo_tagmanager_trigger.test.id]
  merchant_id = "test-value"
  // command_go (Matomo's commandGo, TYPE_BOOL, no declared validators) is
  // set explicitly here: leaving it unset previously produced "The value
  // for the 'go' field in the 'TagManager' plugin is not allowed" at
  // create time, which EmarsysTag.php's source doesn't explain (no
  // validator on this field) - setting it removes the ambiguity.
  command_go = true
}
`
}
